#include &lt;stdio.h&gt;
#include &lt;stdint.h&gt;

void bitwise_demo() {
    uint8_t a = 1; // Binary 0000 0001
    uint8_t b = 2; // Binary 0000 0010

    // LOGICAL AND (&&): Asks "Are both numbers non-zero?" -> TRUE (1)
    if (a && b) printf("Logical && is true.\n");

    // BITWISE AND (&): Asks "Do they share any 1 bits?" -> FALSE (0000 0000)
    if (a & b)  printf("Bitwise & is true.\n"); // This will not execute.
}

#include &lt;stdint.h&gt;

// An ancient systems trick to swap two variables without a temporary third variable.
// Relies on the mathematical identity: (X ^ Y) ^ Y == X
void xor_swap(uint32_t *x, uint32_t *y) {
    if (x == y) return; // Must prevent swapping a memory address with itself (yields 0)

    *x = *x ^ *y; 
    *y = *x ^ *y; // *y now contains original *x
    *x = *x ^ *y; // *x now contains original *y
}

#include &lt;stdint.h&gt;

uint32_t fast_modulo(uint32_t val) {
    // Standard modulo (val % 8) requires CPU division (~20 cycles).
    // Since 8 is a power of 2, we can use bitwise AND with (8 - 1) instead.
    // Binary 7 is 0111. ANDing with 7 strips away all upper bits, leaving the remainder.
    // This evaluates in exactly 1 clock cycle.
    return val & 7; 
}

