#include &lt;stdint.h&gt;

uint32_t fast_multiply(uint32_t val) {
    // Multiplying by 10 conventionally: val * 10;
    // Can be rewritten using purely fast shifts and additions.
    // Since 10 = 8 + 2, we shift by 3 (x8) and shift by 1 (x2).
    return (val << 3) + (val << 1);
}

