#include &lt;stdio.h&gt;

void shift_trap() {
    uint32_t mask = 1;

    // DANGER: Shifting by 32 on a 32-bit integer is Undefined Behavior.
    // Intel x86 hardware actually masks the shift count with 0x1F (31),
    // meaning 32 is treated as 0. The output will be 1, NOT 0!
    uint32_t result = mask << 32;

    printf("Result: %u\n", result);
}

#include &lt;stdint.h&gt;

// C lacks a native bit-rotation operator. We must emulate it.
// A left rotate shifts bits left, and takes the bits falling off the top 
// and inserts them at the bottom.
uint32_t rotl32(uint32_t val, uint32_t shift) {
    // Protect against UB by masking the shift amount to 0-31
    shift &= 31;
    if (shift == 0) return val;

    // Shift left, ORed with the bits falling off shifted right.
    return (val << shift) | (val >> (32 - shift));
}

