// Industry standard macros for bit manipulation. 
// '1U' guarantees unsigned shifts.
#define SET_BIT(REG, N)    ((REG) |=  (1U << (N)))
#define CLEAR_BIT(REG, N)  ((REG) &= ~(1U << (N)))
#define TOGGLE_BIT(REG, N) ((REG) ^=  (1U << (N)))
#define CHECK_BIT(REG, N)  (((REG) >> (N)) & 1U)

#include &lt;stdint.h&gt;

// Packs 3 separate 8-bit colors into a single 32-bit hex code (0x00RRGGBB)
uint32_t pack_rgb(uint8_t r, uint8_t g, uint8_t b) {
    uint32_t color = 0;
    color |= ((uint32_t)r << 16); // Shift Red 16 bits left
    color |= ((uint32_t)g << 8);  // Shift Green 8 bits left
    color |= ((uint32_t)b);       // Leave Blue at bottom
    return color;
}

// Unpacking relies on shifting down and masking out the noise
uint8_t unpack_green(uint32_t color) {
    return (color >> 8) & 0xFF; // Shift Green to bottom, mask out Red
}

#include &lt;stdint.h&gt;

#define PORTA_ADDR 0x40020000 // Physical memory address of the chip's IO port
// Using 'volatile' prevents the compiler from optimizing away the write.
#define PORTA_REG  (*((volatile uint32_t*)PORTA_ADDR))

#define LED_PIN 5

void turn_on_led() {
    // SET_BIT pattern. This reads the current state of PORTA, 
    // activates bit 5, and writes the new state back.
    PORTA_REG |= (1U << LED_PIN);
}

#include &lt;stdint.h&gt;

// Assume bits 2 and 3 control a speed setting (00=Stop, 01=Slow, 10=Fast, 11=Max)
#define SPEED_MASK (3U << 2) // Creates 0000 1100

void set_speed(uint32_t *reg, uint32_t speed_val) {
    // Step 1: Clear the target bits using the inverted mask
    *reg &= ~SPEED_MASK;

    // Step 2: Shift the new value into position and OR it in
    *reg |= (speed_val << 2);
}
